#!/usr/bin/env node
// Generates src/app/core/firebase/firebase.env.generated.ts from
// NG_APP_FIREBASE_* environment variables.
//
// Sources, later wins: .env -> .env.local -> process.env. Vercel/CI inject
// via process.env; local dev uses .env.local. Missing vars become "".
// The generated file is gitignored; firebase.config.ts imports it. Runs via
// the gen:firebase-env npm script (wired into build/start/test) + postinstall.
import { readFileSync, writeFileSync, existsSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';

const root = join(dirname(fileURLToPath(import.meta.url)), '..');

function parseDotenv(file) {
  const path = join(root, file);
  if (!existsSync(path)) return {};
  const out = {};
  for (const line of readFileSync(path, 'utf8').split('\n')) {
    const m = line.match(/^\s*(?:export\s+)?([A-Za-z_][A-Za-z0-9_]*)\s*=\s*(.*)$/);
    if (!m) continue;
    let v = m[2].trim();
    if ((v.startsWith('"') && v.endsWith('"')) || (v.startsWith("'") && v.endsWith("'"))) {
      v = v.slice(1, -1);
    }
    out[m[1]] = v;
  }
  return out;
}

const merged = { ...parseDotenv('.env'), ...parseDotenv('.env.local'), ...process.env };

const KEYS = [
  'NG_APP_FIREBASE_API_KEY',
  'NG_APP_FIREBASE_AUTH_DOMAIN',
  'NG_APP_FIREBASE_PROJECT_ID',
  'NG_APP_FIREBASE_STORAGE_BUCKET',
  'NG_APP_FIREBASE_MESSAGING_SENDER_ID',
  'NG_APP_FIREBASE_APP_ID',
  'NG_APP_FIREBASE_MEASUREMENT_ID',
  'NG_APP_FIREBASE_VAPID_KEY',
];

const values = {};
for (const k of KEYS) values[k] = merged[k] ?? '';

const out = `// AUTO-GENERATED by scripts/gen-firebase-env.mjs — do not edit, do not commit.
// Firebase web config from NG_APP_FIREBASE_* env (.env.local in dev, Vercel env
// in prod). Missing values are empty strings.
/* eslint-disable */
export const firebaseEnv = ${JSON.stringify(values, null, 2)} as const;
`;

writeFileSync(join(root, 'src/app/core/firebase/firebase.env.generated.ts'), out);
const set = KEYS.filter((k) => values[k]).length;
console.log(`[gen-firebase-env] firebase.env.generated.ts written (${set}/${KEYS.length} values present)`);
